// Package scanner_test contains integration tests for the Navidrome media scanner.
// These tests exercise the full scanning pipeline: file discovery → metadata
// extraction → DB persistence, using an in-memory SQLite database and a fake
// in-memory filesystem (storagetest.FakeFS) to avoid real I/O.
package scanner_test

import (
	"context"
	"errors"
	"testing"
	"testing/fstest"

	"github.com/Masterminds/squirrel"
	"github.com/navidrome/navidrome/conf"
	"github.com/navidrome/navidrome/conf/configtest"
	"github.com/navidrome/navidrome/core"
	"github.com/navidrome/navidrome/core/artwork"
	"github.com/navidrome/navidrome/core/metrics"
	"github.com/navidrome/navidrome/core/storage/storagetest"
	"github.com/navidrome/navidrome/db"
	"github.com/navidrome/navidrome/model"
	"github.com/navidrome/navidrome/model/request"
	"github.com/navidrome/navidrome/persistence"
	"github.com/navidrome/navidrome/scanner"
	"github.com/navidrome/navidrome/server/events"
	"github.com/navidrome/navidrome/tests"
)

// integrationEnv bundles the objects needed by each integration test.
type integrationEnv struct {
	ctx context.Context
	ds  *tests.MockDataStore
	s   model.Scanner
	lib model.Library
}

// setupIntegrationEnv creates a fresh, isolated test environment:
//   - loads application config (once, via sync.Once in tests.Init)
//   - saves and later restores conf.Server so each test is independent
//   - registers a fake filesystem under the given schema name
//   - initialises the shared in-memory SQLite schema via db.Init
//   - creates an admin user and a library record
//   - registers a t.Cleanup that wipes the schema after the test
//
// The returned *storagetest.FakeFS is the live filesystem object; callers can
// call Add / Remove / Move / SetError on it to mutate the virtual filesystem
// between scanner runs.
func setupIntegrationEnv(t *testing.T, schema string, files fstest.MapFS) (*integrationEnv, *storagetest.FakeFS) {
	t.Helper()

	// Load base config (DbPath = file::memory:?cache=shared, from tests/navidrome-test.toml).
	// sync.Once ensures this only really executes once per test binary.
	tests.Init(t, false)

	// Snapshot conf.Server now and restore it when the test finishes.
	t.Cleanup(configtest.SetupConfig())

	// Point the scanner at our fake storage scheme.
	conf.Server.MusicFolder = schema + ":///music"
	conf.Server.DevExternalScanner = false

	// Build the fake filesystem and register it for the chosen scheme.
	fakeFS := &storagetest.FakeFS{}
	fakeFS.SetFiles(files)
	storagetest.Register(schema, fakeFS)

	// Context carries the admin user identity expected by scanner internals.
	ctx := request.WithUser(context.Background(), model.User{ID: "123", IsAdmin: true})

	// Ensure the DB schema exists (migrations are idempotent).
	db.Init(ctx)

	// Tear down: wipe all tables after the test so the next test starts clean.
	t.Cleanup(func() {
		if err := tests.ClearDB(); err != nil {
			t.Logf("ClearDB: %v", err)
		}
	})

	// Wire up the real persistence layer against the shared in-memory DB.
	ds := &tests.MockDataStore{RealDS: persistence.New(db.Db())}

	// The scanner requires an admin user to exist in the DB.
	adminUser := model.User{
		ID:          "123",
		UserName:    "admin",
		Name:        "Admin User",
		IsAdmin:     true,
		NewPassword: "password",
	}
	if err := ds.User(ctx).Put(&adminUser); err != nil {
		t.Fatalf("create admin user: %v", err)
	}

	// Create the scanner under test.
	s := scanner.New(ctx, ds, artwork.NoopCacheWarmer(), events.NoopBroker(),
		core.NewPlaylists(ds), metrics.NewNoopInstance())

	// Create the single library that points at the fake storage.
	lib := model.Library{
		ID:   1,
		Name: "Integration Test Library",
		Path: schema + ":///music",
	}
	if err := ds.Library(ctx).Put(&lib); err != nil {
		t.Fatalf("create library: %v", err)
	}

	return &integrationEnv{ctx: ctx, ds: ds, s: s, lib: lib}, fakeFS
}

// ────────────────────────────────────────────────────────────────────────────
// Test 1 – Full scan: file discovery, album creation, folder creation
// ────────────────────────────────────────────────────────────────────────────

// TestScannerIntegration_FullScan verifies that a full scan imports every audio
// file, creates corresponding album records with correct song counts, and
// discovers the expected folder hierarchy.
func TestScannerIntegration_FullScan(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping integration test in short mode")
	}

	revolver := storagetest.Template(map[string]any{
		"albumartist": "The Beatles",
		"album":       "Revolver",
		"year":        1966,
	})

	env, _ := setupIntegrationEnv(t, "itfull", fstest.MapFS{
		"The Beatles/Revolver/01 - Taxman.mp3":        revolver(storagetest.Track(1, "Taxman")),
		"The Beatles/Revolver/02 - Eleanor Rigby.mp3": revolver(storagetest.Track(2, "Eleanor Rigby")),
		"The Beatles/Revolver/03 - Love You To.mp3":   revolver(storagetest.Track(3, "Love You To")),
	})

	// ── Stage: full scan ──────────────────────────────────────────────────
	_, err := env.s.ScanAll(env.ctx, true)
	if err != nil {
		t.Fatalf("ScanAll: %v", err)
	}

	// ── Stage: file persistence ───────────────────────────────────────────
	mfs, err := env.ds.MediaFile(env.ctx).GetAll()
	if err != nil {
		t.Fatalf("MediaFile.GetAll: %v", err)
	}
	if got := len(mfs); got != 3 {
		t.Errorf("MediaFile count: want 3, got %d", got)
	}

	// ── Stage: album persistence ──────────────────────────────────────────
	albums, err := env.ds.Album(env.ctx).GetAll(model.QueryOptions{Sort: "name"})
	if err != nil {
		t.Fatalf("Album.GetAll: %v", err)
	}
	if got := len(albums); got != 1 {
		t.Fatalf("Album count: want 1, got %d", got)
	}
	if albums[0].Name != "Revolver" {
		t.Errorf("Album name: want %q, got %q", "Revolver", albums[0].Name)
	}
	if albums[0].SongCount != 3 {
		t.Errorf("Album.SongCount: want 3, got %d", albums[0].SongCount)
	}

	// ── Stage: folder discovery ───────────────────────────────────────────
	folders, err := env.ds.Folder(env.ctx).GetAll(model.QueryOptions{
		Filters: squirrel.Eq{"library_id": env.lib.ID},
	})
	if err != nil {
		t.Fatalf("Folder.GetAll: %v", err)
	}
	// Expect at least: "." (root), "The Beatles", "Revolver"
	if got := len(folders); got < 3 {
		t.Errorf("Folder count: want >= 3, got %d", got)
	}
}

// ────────────────────────────────────────────────────────────────────────────
// Test 2 – Metadata extraction: title, artist, album, year, track number
// ────────────────────────────────────────────────────────────────────────────

// TestScannerIntegration_MetadataExtraction verifies that the scanner correctly
// reads and persists track-level metadata from simulated audio files.
func TestScannerIntegration_MetadataExtraction(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping integration test in short mode")
	}

	pink := storagetest.Template(map[string]any{
		"albumartist": "Pink Floyd",
		"artist":      "Pink Floyd",
		"album":       "The Dark Side of the Moon",
		"year":        1973,
		"genre":       "Progressive Rock",
	})

	env, _ := setupIntegrationEnv(t, "itmeta", fstest.MapFS{
		"Pink Floyd/DSOTM/01 - Speak to Me.mp3": pink(storagetest.Track(1, "Speak to Me")),
		"Pink Floyd/DSOTM/02 - Breathe.mp3":     pink(storagetest.Track(2, "Breathe")),
	})

	if _, err := env.s.ScanAll(env.ctx, true); err != nil {
		t.Fatalf("ScanAll: %v", err)
	}

	mfs, err := env.ds.MediaFile(env.ctx).GetAll(model.QueryOptions{Sort: "track_number"})
	if err != nil {
		t.Fatalf("MediaFile.GetAll: %v", err)
	}
	if len(mfs) != 2 {
		t.Fatalf("track count: want 2, got %d", len(mfs))
	}

	first := mfs[0]
	checks := []struct {
		field string
		want  any
		got   any
	}{
		{"Title", "Speak to Me", first.Title},
		{"AlbumArtist", "Pink Floyd", first.AlbumArtist},
		{"Album", "The Dark Side of the Moon", first.Album},
		{"Year", 1973, first.Year},
		{"TrackNumber", 1, first.TrackNumber},
	}
	for _, c := range checks {
		if c.want != c.got {
			t.Errorf("track[0].%s: want %v, got %v", c.field, c.want, c.got)
		}
	}

	second := mfs[1]
	if second.TrackNumber != 2 {
		t.Errorf("track[1].TrackNumber: want 2, got %d", second.TrackNumber)
	}
	if second.Title != "Breathe" {
		t.Errorf("track[1].Title: want %q, got %q", "Breathe", second.Title)
	}
}

// ────────────────────────────────────────────────────────────────────────────
// Test 3 – Artist and album record creation
// ────────────────────────────────────────────────────────────────────────────

// TestScannerIntegration_ArtistAndAlbumCreation verifies that the scanner
// creates artist records, links them to albums, and calculates basic stats.
func TestScannerIntegration_ArtistAndAlbumCreation(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping integration test in short mode")
	}

	led := storagetest.Template(map[string]any{
		"albumartist": "Led Zeppelin",
		"album":       "IV",
		"year":        1971,
	})

	env, _ := setupIntegrationEnv(t, "itartist", fstest.MapFS{
		"Led Zeppelin/IV/01 - Black Dog.mp3":     led(storagetest.Track(1, "Black Dog")),
		"Led Zeppelin/IV/02 - Rock and Roll.mp3": led(storagetest.Track(2, "Rock and Roll")),
		"Led Zeppelin/IV/03 - The Battle.mp3":    led(storagetest.Track(3, "The Battle of Evermore")),
	})

	if _, err := env.s.ScanAll(env.ctx, true); err != nil {
		t.Fatalf("ScanAll: %v", err)
	}

	// ── Artist must be created ────────────────────────────────────────────
	artists, err := env.ds.Artist(env.ctx).GetAll(model.QueryOptions{
		Filters: squirrel.Eq{"name": "Led Zeppelin"},
	})
	if err != nil {
		t.Fatalf("Artist.GetAll: %v", err)
	}
	if len(artists) != 1 {
		t.Fatalf("artist count: want 1, got %d", len(artists))
	}
	if artists[0].Name != "Led Zeppelin" {
		t.Errorf("artist name: want %q, got %q", "Led Zeppelin", artists[0].Name)
	}

	// ── Album must be created with correct song count ─────────────────────
	albums, err := env.ds.Album(env.ctx).GetAll(model.QueryOptions{
		Filters: squirrel.Eq{"album.name": "IV"},
	})
	if err != nil {
		t.Fatalf("Album.GetAll: %v", err)
	}
	if len(albums) != 1 {
		t.Fatalf("album count: want 1, got %d", len(albums))
	}
	if albums[0].SongCount != 3 {
		t.Errorf("album.SongCount: want 3, got %d", albums[0].SongCount)
	}
	if albums[0].AlbumArtist != "Led Zeppelin" {
		t.Errorf("album.AlbumArtist: want %q, got %q", "Led Zeppelin", albums[0].AlbumArtist)
	}

	// ── Artist must reference the album's artist ID ────────────────────────
	if albums[0].AlbumArtistID == "" {
		t.Error("album.AlbumArtistID is empty, expected a non-empty artist ID")
	}
	if albums[0].AlbumArtistID != artists[0].ID {
		t.Errorf("album.AlbumArtistID: want %q (Led Zeppelin), got %q", artists[0].ID, albums[0].AlbumArtistID)
	}
}

// ────────────────────────────────────────────────────────────────────────────
// Test 4 – Incremental scan: unchanged library produces no duplicate records
// ────────────────────────────────────────────────────────────────────────────

// TestScannerIntegration_IncrementalScanNoChanges verifies that running a
// second (incremental) scan against an unchanged library does not produce
// additional DB records — i.e. the scanner is idempotent for unchanged files.
func TestScannerIntegration_IncrementalScanNoChanges(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping integration test in short mode")
	}

	beatles := storagetest.Template(map[string]any{
		"albumartist": "The Beatles",
		"album":       "Help!",
		"year":        1965,
	})

	env, _ := setupIntegrationEnv(t, "itincr", fstest.MapFS{
		"The Beatles/Help!/01 - Help!.mp3":            beatles(storagetest.Track(1, "Help!")),
		"The Beatles/Help!/02 - The Night Before.mp3": beatles(storagetest.Track(2, "The Night Before")),
	})

	// ── First scan (full) ─────────────────────────────────────────────────
	if _, err := env.s.ScanAll(env.ctx, true); err != nil {
		t.Fatalf("first ScanAll: %v", err)
	}

	trackCountAfterFirst, err := env.ds.MediaFile(env.ctx).CountAll()
	if err != nil {
		t.Fatalf("CountAll after first scan: %v", err)
	}
	if trackCountAfterFirst != 2 {
		t.Fatalf("expected 2 tracks after first scan, got %d", trackCountAfterFirst)
	}

	albumCountAfterFirst, err := env.ds.Album(env.ctx).CountAll()
	if err != nil {
		t.Fatalf("Album.CountAll after first scan: %v", err)
	}

	// ── Second scan (incremental, no file changes) ────────────────────────
	if _, err := env.s.ScanAll(env.ctx, false); err != nil {
		t.Fatalf("second ScanAll: %v", err)
	}

	trackCountAfterSecond, err := env.ds.MediaFile(env.ctx).CountAll()
	if err != nil {
		t.Fatalf("CountAll after second scan: %v", err)
	}
	if trackCountAfterSecond != trackCountAfterFirst {
		t.Errorf("incremental scan duplicated tracks: was %d, now %d",
			trackCountAfterFirst, trackCountAfterSecond)
	}

	albumCountAfterSecond, err := env.ds.Album(env.ctx).CountAll()
	if err != nil {
		t.Fatalf("Album.CountAll after second scan: %v", err)
	}
	if albumCountAfterSecond != albumCountAfterFirst {
		t.Errorf("incremental scan duplicated albums: was %d, now %d",
			albumCountAfterFirst, albumCountAfterSecond)
	}
}

// ────────────────────────────────────────────────────────────────────────────
// Test 5 – File deletion detection
// ────────────────────────────────────────────────────────────────────────────

// TestScannerIntegration_FileDeletion verifies that when a file is removed from
// the virtual filesystem and the library is re-scanned, the corresponding DB
// record is marked as missing (Missing == true) while other records remain
// intact.
func TestScannerIntegration_FileDeletion(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping integration test in short mode")
	}

	dylan := storagetest.Template(map[string]any{
		"albumartist": "Bob Dylan",
		"album":       "Highway 61 Revisited",
		"year":        1965,
	})

	env, fakeFS := setupIntegrationEnv(t, "itdel", fstest.MapFS{
		"Bob Dylan/Hwy61/01 - Like a Rolling Stone.mp3": dylan(storagetest.Track(1, "Like a Rolling Stone")),
		"Bob Dylan/Hwy61/02 - Tombstone Blues.mp3":      dylan(storagetest.Track(2, "Tombstone Blues")),
		"Bob Dylan/Hwy61/03 - Ballad of a Thin Man.mp3": dylan(storagetest.Track(3, "Ballad of a Thin Man")),
	})

	// ── Initial full scan ─────────────────────────────────────────────────
	if _, err := env.s.ScanAll(env.ctx, true); err != nil {
		t.Fatalf("initial ScanAll: %v", err)
	}

	initialCount, err := env.ds.MediaFile(env.ctx).CountAll()
	if err != nil {
		t.Fatalf("CountAll: %v", err)
	}
	if initialCount != 3 {
		t.Fatalf("expected 3 tracks after initial scan, got %d", initialCount)
	}

	// ── Remove one file ───────────────────────────────────────────────────
	fakeFS.Remove("Bob Dylan/Hwy61/02 - Tombstone Blues.mp3")

	// ── Re-scan (incremental) ─────────────────────────────────────────────
	if _, err := env.s.ScanAll(env.ctx, false); err != nil {
		t.Fatalf("re-scan ScanAll: %v", err)
	}

	// ── Deleted file must be marked Missing ───────────────────────────────
	list, err := env.ds.MediaFile(env.ctx).FindByPaths(
		[]string{"Bob Dylan/Hwy61/02 - Tombstone Blues.mp3"},
	)
	if err != nil {
		t.Fatalf("FindByPaths: %v", err)
	}
	if len(list) != 1 {
		t.Fatalf("expected 1 record for deleted path, got %d", len(list))
	}
	if !list[0].Missing {
		t.Error("deleted file: Missing should be true, got false")
	}

	// ── Remaining files must NOT be marked missing ────────────────────────
	presentCount, err := env.ds.MediaFile(env.ctx).CountAll(model.QueryOptions{
		Filters: squirrel.Eq{"missing": false},
	})
	if err != nil {
		t.Fatalf("CountAll(non-missing): %v", err)
	}
	if presentCount != 2 {
		t.Errorf("non-missing track count: want 2, got %d", presentCount)
	}
}

// ────────────────────────────────────────────────────────────────────────────
// Test 6 – Corrupt / unreadable file (negative case)
// ────────────────────────────────────────────────────────────────────────────

// TestScannerIntegration_CorruptFile verifies that a simulated read error on
// one audio file does not abort the scan: the scanner should return without a
// hard error, emit at least one warning, and still import the healthy files.
func TestScannerIntegration_CorruptFile(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping integration test in short mode")
	}

	queen := storagetest.Template(map[string]any{
		"albumartist": "Queen",
		"album":       "A Night at the Opera",
		"year":        1975,
	})

	env, fakeFS := setupIntegrationEnv(t, "itcorrupt", fstest.MapFS{
		"Queen/Opera/01 - Bohemian Rhapsody.mp3":     queen(storagetest.Track(1, "Bohemian Rhapsody")),
		"Queen/Opera/02 - You're My Best Friend.mp3": queen(storagetest.Track(2, "You're My Best Friend")),
		"Queen/Opera/03 - Love of My Life.mp3":       queen(storagetest.Track(3, "Love of My Life")),
	})

	// Inject a read error on track 1 to simulate a corrupt file.
	fakeFS.SetError("Queen/Opera/01 - Bohemian Rhapsody.mp3",
		errors.New("simulated read error: corrupt file"))

	// ── Scan must not return a hard error ─────────────────────────────────
	warnings, err := env.s.ScanAll(env.ctx, true)
	if err != nil {
		t.Fatalf("ScanAll should not return a hard error for a single corrupt file, got: %v", err)
	}
	if len(warnings) == 0 {
		t.Log("note: expected at least one warning for the corrupt file (implementation may vary)")
	}

	// ── Healthy files must still be imported ──────────────────────────────
	mfs, err := env.ds.MediaFile(env.ctx).GetAll()
	if err != nil {
		t.Fatalf("MediaFile.GetAll: %v", err)
	}

	titles := make(map[string]bool, len(mfs))
	for _, m := range mfs {
		titles[m.Title] = true
	}

	healthyTracks := []string{"You're My Best Friend", "Love of My Life"}
	for _, want := range healthyTracks {
		if !titles[want] {
			t.Errorf("expected healthy track %q to be imported; imported titles: %v", want, titles)
		}
	}

	// The corrupt file should NOT appear in the DB (it couldn't be read).
	if titles["Bohemian Rhapsody"] {
		t.Log("note: corrupt track was unexpectedly imported (may depend on where the error occurs)")
	}
}

// ────────────────────────────────────────────────────────────────────────────
// Test 7 – Tag update detection
// ────────────────────────────────────────────────────────────────────────────

// TestScannerIntegration_TagUpdate verifies that when a file's tags are
// modified (simulated via FakeFS.UpdateTags, which bumps the ModTime), a
// subsequent full scan picks up the changes and updates the DB record.
func TestScannerIntegration_TagUpdate(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping integration test in short mode")
	}

	stones := storagetest.Template(map[string]any{
		"albumartist": "The Rolling Stones",
		"album":       "Exile on Main St.",
		"year":        1972,
	})

	env, fakeFS := setupIntegrationEnv(t, "ittag", fstest.MapFS{
		"Stones/Exile/01 - Rocks Off.mp3":   stones(storagetest.Track(1, "Rocks Off")),
		"Stones/Exile/02 - Rip This Joint.mp3": stones(storagetest.Track(2, "Rip This Joint")),
	})

	// ── First full scan ───────────────────────────────────────────────────
	if _, err := env.s.ScanAll(env.ctx, true); err != nil {
		t.Fatalf("first ScanAll: %v", err)
	}

	// Confirm original comment is absent.
	list, err := env.ds.MediaFile(env.ctx).FindByPaths([]string{"Stones/Exile/01 - Rocks Off.mp3"})
	if err != nil {
		t.Fatalf("FindByPaths (before update): %v", err)
	}
	if len(list) != 1 {
		t.Fatalf("expected 1 record for Rocks Off, got %d", len(list))
	}
	if list[0].Comment != "" {
		t.Errorf("expected empty Comment before tag update, got %q", list[0].Comment)
	}

	// ── Update a tag (bumps ModTime so the scanner detects the change) ────
	fakeFS.UpdateTags("Stones/Exile/01 - Rocks Off.mp3", map[string]any{
		"comment": "best opener ever",
	})

	// ── Second full scan ──────────────────────────────────────────────────
	if _, err := env.s.ScanAll(env.ctx, true); err != nil {
		t.Fatalf("second ScanAll: %v", err)
	}

	list, err = env.ds.MediaFile(env.ctx).FindByPaths([]string{"Stones/Exile/01 - Rocks Off.mp3"})
	if err != nil {
		t.Fatalf("FindByPaths (after update): %v", err)
	}
	if len(list) != 1 {
		t.Fatalf("expected 1 record for Rocks Off after update, got %d", len(list))
	}
	if list[0].Comment != "best opener ever" {
		t.Errorf("Comment after tag update: want %q, got %q", "best opener ever", list[0].Comment)
	}
}

