283: func (s *scannerImpl) runOptimize(ctx context.Context) func() error {
284: 	return func() error {
285: 		start := time.Now()
286: 		db.Optimize(ctx)
287: 		log.Debug(ctx, "Scanner: Optimized DB", "elapsed", time.Since(start))
288: 		return nil
289: 	}
290: }
