328: type phase[T any] interface {
329: 	producer() ppl.Producer[T]
330: 	stages() []ppl.Stage[T]
331: 	finalize(error) error
332: 	description() string
333: }
334: 
335: func runPhase[T any](ctx context.Context, phaseNum int, phase phase[T]) func() error {
336: 	return func() error {
337: 		log.Debug(ctx, fmt.Sprintf("Scanner: Starting phase %d: %s", phaseNum, phase.description()))
338: 		start := time.Now()
339: 
340: 		producer := phase.producer()
341: 		stages := phase.stages()
342: 
343: 		// Prepend a counter stage to the phase's pipeline
344: 		counter, countStageFn := countTasks[T]()
345: 		stages = append([]ppl.Stage[T]{ppl.NewStage(countStageFn, ppl.Name("count tasks"))}, stages...)
346: 
347: 		var err error
348: 		if log.IsGreaterOrEqualTo(log.LevelDebug) {
349: 			var m *ppl.Metrics
350: 			m, err = ppl.Measure(producer, stages...)
351: 			log.Info(ctx, "Scanner: "+m.String(), err)
352: 		} else {
353: 			err = ppl.Do(producer, stages...)
354: 		}
355: 
356: 		err = phase.finalize(err)
357: 
358: 		if err != nil {
359: 			log.Error(ctx, fmt.Sprintf("Scanner: Error processing libraries in phase %d", phaseNum), "elapsed", time.Since(start), err)
360: 		} else {
361: 			log.Debug(ctx, fmt.Sprintf("Scanner: Finished phase %d", phaseNum), "elapsed", time.Since(start), "totalTasks", counter.Load())
362: 		}
363: 
364: 		return err
365: 	}
366: }
367: 
368: func countTasks[T any]() (*atomic.Int64, func(T) (T, error)) {
369: 	counter := atomic.Int64{}
370: 	return &counter, func(in T) (T, error) {
371: 		counter.Add(1)
372: 		return in, nil
373: 	}
374: }
