109: // getLastScanTime returns the most recent scan time across all libraries
110: func (s *controller) getLastScanTime(ctx context.Context) (time.Time, error) {
111: 	libs, err := s.ds.Library(ctx).GetAll(model.QueryOptions{
112: 		Sort:  "last_scan_at",
113: 		Order: "desc",
114: 		Max:   1,
115: 	})
116: 	if err != nil {
117: 		return time.Time{}, fmt.Errorf("getting libraries: %w", err)
118: 	}
119: 
120: 	if len(libs) == 0 {
121: 		return time.Time{}, nil
122: 	}
123: 
124: 	return libs[0].LastScanAt, nil
125: }
