127: // getScanInfo retrieves scan status from the database
128: func (s *controller) getScanInfo(ctx context.Context) (scanType string, elapsed time.Duration, lastErr string) {
129: 	lastErr, _ = s.ds.Property(ctx).DefaultGet(consts.LastScanErrorKey, "")
130: 	scanType, _ = s.ds.Property(ctx).DefaultGet(consts.LastScanTypeKey, "")
131: 	startTimeStr, _ := s.ds.Property(ctx).DefaultGet(consts.LastScanStartTimeKey, "")
132: 
133: 	if startTimeStr != "" {
134: 		startTime, err := time.Parse(time.RFC3339, startTimeStr)
135: 		if err == nil {
136: 			if running.Load() {
137: 				elapsed = time.Since(startTime)
138: 			} else {
139: 				// If scan is not running, calculate elapsed time using the most recent scan time
140: 				lastScanTime, err := s.getLastScanTime(ctx)
141: 				if err == nil && !lastScanTime.IsZero() {
142: 					elapsed = lastScanTime.Sub(startTime)
143: 				}
144: 			}
145: 		}
146: 	}
147: 
148: 	return scanType, elapsed, lastErr
149: }
