204: func (s *controller) ScanFolders(requestCtx context.Context, fullScan bool, targets []model.ScanTarget) ([]string, error) {
205: 	release, err := lockScan(requestCtx)
206: 	if err != nil {
207: 		return nil, err
208: 	}
209: 	defer release()
210: 
211: 	// Prepare the context for the scan
212: 	ctx := request.AddValues(s.rootCtx, requestCtx)
213: 	ctx = auth.WithAdminUser(ctx, s.ds)
214: 
215: 	// Send the initial scan status event
216: 	s.sendMessage(ctx, &events.ScanStatus{Scanning: true, Count: 0, FolderCount: 0})
217: 	progress := make(chan *ProgressInfo, 100)
218: 	go func() {
219: 		defer close(progress)
220: 		scanner := s.getScanner()
221: 		scanner.scanFolders(ctx, fullScan, targets, progress)
222: 	}()
223: 
224: 	// Wait for the scan to finish, sending progress events to all connected clients
225: 	scanWarnings, scanError := s.trackProgress(ctx, progress)
226: 	for _, w := range scanWarnings {
227: 		log.Warn(ctx, fmt.Sprintf("Scan warning: %s", w))
228: 	}
229: 	// Store scan error in database so it can be displayed in the UI
230: 	if scanError != nil {
231: 		_ = s.ds.Property(ctx).Put(consts.LastScanErrorKey, scanError.Error())
232: 	}
233: 	// If changes were detected, send a refresh event to all clients
234: 	if s.changesDetected {
235: 		log.Debug(ctx, "Library changes imported. Sending refresh event")
236: 		s.broker.SendBroadcastMessage(ctx, &events.RefreshResource{})
237: 	}
238: 	// Send the final scan status event, with totals
239: 	if count, folderCount, err := s.getCounters(ctx); err != nil {
240: 		s.metrics.WriteAfterScanMetrics(ctx, false)
241: 		return scanWarnings, err
242: 	} else {
243: 		scanType, elapsed, lastErr := s.getScanInfo(ctx)
244: 		s.metrics.WriteAfterScanMetrics(ctx, true)
245: 		s.sendMessage(ctx, &events.ScanStatus{
246: 			Scanning:    false,
247: 			Count:       count,
248: 			FolderCount: folderCount,
249: 			Error:       lastErr,
250: 			ScanType:    scanType,
251: 			ElapsedTime: elapsed,
252: 		})
253: 	}
254: 	return scanWarnings, scanError
255: }
256: 
257: // This is a global variable that is used to prevent multiple scans from running at the same time.
258: // "There can be only one" - https://youtu.be/sqcLjcSloXs?si=VlsjEOjTJZ68zIyg
259: var running atomic.Bool
260: 
261: func lockScan(ctx context.Context) (func(), error) {
262: 	if !running.CompareAndSwap(false, true) {
263: 		log.Debug(ctx, "Scanner already running, ignoring request")
264: 		return func() {}, ErrAlreadyScanning
265: 	}
266: 	return func() {
267: 		running.Store(false)
268: 	}, nil
269: }
270: 
271: func (s *controller) trackProgress(ctx context.Context, progress <-chan *ProgressInfo) ([]string, error) {
272: 	s.count.Store(0)
273: 	s.folderCount.Store(0)
274: 	s.changesDetected = false
275: 
276: 	var warnings []string
277: 	var errs []error
278: 	for p := range pl.ReadOrDone(ctx, progress) {
279: 		if p.Error != "" {
280: 			errs = append(errs, errors.New(p.Error))
281: 			continue
282: 		}
283: 		if p.Warning != "" {
284: 			warnings = append(warnings, p.Warning)
285: 			continue
286: 		}
287: 		if p.ChangesDetected {
288: 			s.changesDetected = true
289: 			continue
290: 		}
291: 		s.count.Add(p.FileCount)
292: 		if p.FileCount > 0 {
293: 			s.folderCount.Add(1)
294: 		}
295: 
296: 		scanType, elapsed, lastErr := s.getScanInfo(ctx)
297: 		status := &events.ScanStatus{
298: 			Scanning:    true,
299: 			Count:       int64(s.count.Load()),
300: 			FolderCount: int64(s.folderCount.Load()),
301: 			Error:       lastErr,
302: 			ScanType:    scanType,
303: 			ElapsedTime: elapsed,
304: 		}
305: 		if s.limiter != nil && !p.ForceUpdate {
306: 			s.limiter.Do(func() { s.sendMessage(ctx, status) })
307: 		} else {
308: 			s.sendMessage(ctx, status)
309: 		}
310: 	}
311: 	return warnings, errors.Join(errs...)
312: }
313: 
314: func (s *controller) sendMessage(ctx context.Context, status *events.ScanStatus) {
315: 	s.broker.SendBroadcastMessage(ctx, status)
316: }
