2: package storagetest
3: 
4: import (
5: 	"encoding/json"
6: 	"errors"
7: 	"fmt"
8: 	"io/fs"
9: 	"maps"
10: 	"net/url"
11: 	"path"
12: 	"testing/fstest"
13: 	"time"
14: 
15: 	"github.com/navidrome/navidrome/core/storage"
16: 	"github.com/navidrome/navidrome/log"
17: 	"github.com/navidrome/navidrome/model/metadata"
18: 	"github.com/navidrome/navidrome/utils/random"
19: )
20: 
21: // FakeStorage is a fake storage that provides a FakeFS.
22: // It is used for testing purposes.
23: type FakeStorage struct{ fs *FakeFS }
24: 
25: // Register registers the FakeStorage for the given scheme. To use it, set the model.Library's Path to "fake:///music",
26: // and register a FakeFS with schema = "fake". The storage registered will always return the same FakeFS instance.
27: func Register(schema string, fs *FakeFS) {
28: 	storage.Register(schema, func(url url.URL) storage.Storage { return &FakeStorage{fs: fs} })
29: }
30: 
31: func (s FakeStorage) FS() (storage.MusicFS, error) {
32: 	return s.fs, nil
33: }
34: 
35: // FakeFS is a fake filesystem that can be used for testing purposes.
36: // It implements the storage.MusicFS interface and keeps all files in memory, by using a fstest.MapFS internally.
37: // You must NOT add files directly in the MapFS property, but use SetFiles and its other methods instead.
38: // This is because the FakeFS keeps track of the latest modification time of directories, simulating the
39: // behavior of a real filesystem, and you should not bypass this logic.
40: type FakeFS struct {
41: 	fstest.MapFS
42: 	properInit bool
43: }
44: 
45: func (ffs *FakeFS) SetFiles(files fstest.MapFS) {
46: 	ffs.properInit = true
47: 	ffs.MapFS = files
48: 	ffs.createDirTimestamps()
49: }
50: 
51: func (ffs *FakeFS) Add(filePath string, file *fstest.MapFile, when ...time.Time) {
52: 	if len(when) == 0 {
53: 		when = append(when, time.Now())
54: 	}
55: 	ffs.MapFS[filePath] = file
56: 	ffs.touchContainingFolder(filePath, when[0])
57: 	ffs.createDirTimestamps()
58: }
59: 
60: func (ffs *FakeFS) Remove(filePath string, when ...time.Time) *fstest.MapFile {
61: 	filePath = path.Clean(filePath)
62: 	if len(when) == 0 {
63: 		when = append(when, time.Now())
64: 	}
65: 	if f, ok := ffs.MapFS[filePath]; ok {
66: 		ffs.touchContainingFolder(filePath, when[0])
67: 		delete(ffs.MapFS, filePath)
68: 		return f
69: 	}
70: 	return nil
71: }
72: 
73: func (ffs *FakeFS) Move(srcPath string, destPath string, when ...time.Time) {
74: 	if len(when) == 0 {
75: 		when = append(when, time.Now())
76: 	}
77: 	srcPath = path.Clean(srcPath)
78: 	destPath = path.Clean(destPath)
79: 	ffs.MapFS[destPath] = ffs.MapFS[srcPath]
80: 	ffs.touchContainingFolder(destPath, when[0])
81: 	ffs.Remove(srcPath, when...)
82: }
83: 
84: // Touch sets the modification time of a file.
85: func (ffs *FakeFS) Touch(filePath string, when ...time.Time) {
86: 	if len(when) == 0 {
87: 		when = append(when, time.Now())
88: 	}
89: 	filePath = path.Clean(filePath)
90: 	file, ok := ffs.MapFS[filePath]
91: 	if ok {
92: 		file.ModTime = when[0]
93: 	} else {
94: 		ffs.MapFS[filePath] = &fstest.MapFile{ModTime: when[0]}
95: 	}
96: 	ffs.touchContainingFolder(filePath, file.ModTime)
97: }
98: 
99: func (ffs *FakeFS) touchContainingFolder(filePath string, ts time.Time) {
100: 	dir := path.Dir(filePath)
101: 	dirFile, ok := ffs.MapFS[dir]
102: 	if !ok {
103: 		log.Fatal("Directory not found. Forgot to call SetFiles?", "file", filePath)
104: 	}
105: 	if dirFile.ModTime.Before(ts) {
106: 		dirFile.ModTime = ts
107: 	}
108: }
109: 
110: // SetError sets an error that will be returned when trying to read the file.
111: func (ffs *FakeFS) SetError(filePath string, err error) {
112: 	filePath = path.Clean(filePath)
113: 	if ffs.MapFS[filePath] == nil {
114: 		ffs.MapFS[filePath] = &fstest.MapFile{Data: []byte{}}
115: 	}
116: 	ffs.MapFS[filePath].Sys = err
117: 	ffs.Touch(filePath)
118: }
119: 
120: // ClearError clears the error set by SetError.
121: func (ffs *FakeFS) ClearError(filePath string) {
122: 	filePath = path.Clean(filePath)
123: 	if file := ffs.MapFS[filePath]; file != nil {
124: 		file.Sys = nil
125: 	}
126: 	ffs.Touch(filePath)
127: }
128: 
129: func (ffs *FakeFS) UpdateTags(filePath string, newTags map[string]any, when ...time.Time) {
130: 	f, ok := ffs.MapFS[filePath]
131: 	if !ok {
132: 		panic(fmt.Errorf("file %s not found", filePath))
133: 	}
134: 	var tags map[string]any
135: 	err := json.Unmarshal(f.Data, &tags)
136: 	if err != nil {
137: 		panic(err)
138: 	}
139: 	maps.Copy(tags, newTags)
140: 	data, _ := json.Marshal(tags)
141: 	f.Data = data
142: 	ffs.Touch(filePath, when...)
143: }
144: 
145: // createDirTimestamps loops through all entries and create/updates directories entries in the map with the
146: // latest ModTime from any children of that directory.
147: func (ffs *FakeFS) createDirTimestamps() bool {
148: 	var changed bool
149: 	for filePath, file := range ffs.MapFS {
150: 		dir := path.Dir(filePath)
151: 		dirFile, ok := ffs.MapFS[dir]
152: 		if !ok {
153: 			dirFile = &fstest.MapFile{Mode: fs.ModeDir}
154: 			ffs.MapFS[dir] = dirFile
155: 		}
156: 		if dirFile.ModTime.IsZero() {
157: 			dirFile.ModTime = file.ModTime
158: 			changed = true
159: 		}
160: 	}
161: 	if changed {
162: 		// If we updated any directory, we need to re-run the loop to create any parent directories
163: 		ffs.createDirTimestamps()
164: 	}
165: 	return changed
166: }
167: 
168: func ModTime(ts string) map[string]any   { return map[string]any{fakeFileInfoModTime: ts} }
169: func BirthTime(ts string) map[string]any { return map[string]any{fakeFileInfoBirthTime: ts} }
170: 
171: func Template(t ...map[string]any) func(...map[string]any) *fstest.MapFile {
172: 	return func(tags ...map[string]any) *fstest.MapFile {
173: 		return MP3(append(t, tags...)...)
174: 	}
175: }
176: 
177: func Track(num int, title string, tags ...map[string]any) map[string]any {
178: 	ts := audioProperties("mp3", 320)
179: 	ts["title"] = title
180: 	ts["track"] = num
181: 	for _, t := range tags {
182: 		maps.Copy(ts, t)
183: 	}
184: 	return ts
185: }
186: 
187: func MP3(tags ...map[string]any) *fstest.MapFile {
188: 	ts := audioProperties("mp3", 320)
189: 	if _, ok := ts[fakeFileInfoSize]; !ok {
190: 		duration := ts["duration"].(int64)
191: 		bitrate := ts["bitrate"].(int)
192: 		ts[fakeFileInfoSize] = duration * int64(bitrate) / 8 * 1000
193: 	}
194: 	return File(append([]map[string]any{ts}, tags...)...)
195: }
196: 
197: func File(tags ...map[string]any) *fstest.MapFile {
198: 	ts := map[string]any{}
199: 	for _, t := range tags {
200: 		maps.Copy(ts, t)
201: 	}
202: 	modTime := time.Now()
203: 	if mt, ok := ts[fakeFileInfoModTime]; !ok {
204: 		ts[fakeFileInfoModTime] = time.Now().Format(time.RFC3339)
205: 	} else {
206: 		modTime, _ = time.Parse(time.RFC3339, mt.(string))
207: 	}
208: 	if _, ok := ts[fakeFileInfoBirthTime]; !ok {
209: 		ts[fakeFileInfoBirthTime] = time.Now().Format(time.RFC3339)
210: 	}
211: 	if _, ok := ts[fakeFileInfoMode]; !ok {
212: 		ts[fakeFileInfoMode] = fs.ModePerm
213: 	}
214: 	data, _ := json.Marshal(ts)
215: 	if _, ok := ts[fakeFileInfoSize]; !ok {
216: 		ts[fakeFileInfoSize] = int64(len(data))
217: 	}
218: 	return &fstest.MapFile{Data: data, ModTime: modTime, Mode: ts[fakeFileInfoMode].(fs.FileMode)}
219: }
220: 
221: func audioProperties(suffix string, bitrate int) map[string]any {
222: 	duration := random.Int64N(300) + 120
223: 	return map[string]any{
224: 		"suffix":     suffix,
225: 		"bitrate":    bitrate,
226: 		"duration":   duration,
227: 		"samplerate": 44100,
228: 		"bitdepth":   16,
229: 		"channels":   2,
230: 	}
231: }
232: 
233: func (ffs *FakeFS) ReadTags(paths ...string) (map[string]metadata.Info, error) {
234: 	if !ffs.properInit {
235: 		log.Fatal("FakeFS not initialized properly. Use SetFiles")
236: 	}
237: 	result := make(map[string]metadata.Info)
238: 	var errs []error
239: 	for _, file := range paths {
240: 		p, err := ffs.parseFile(file)
241: 		if err != nil {
242: 			log.Warn("Error reading metadata from file", "file", file, "err", err)
243: 			errs = append(errs, err)
244: 		} else {
245: 			result[file] = *p
246: 		}
247: 	}
248: 	if len(errs) > 0 {
249: 		return result, fmt.Errorf("errors reading metadata: %w", errors.Join(errs...))
250: 	}
251: 	return result, nil
252: }
253: 
254: func (ffs *FakeFS) parseFile(filePath string) (*metadata.Info, error) {
255: 	// Check if it should throw an error when reading this file
256: 	stat, err := ffs.Stat(filePath)
257: 	if err != nil {
258: 		return nil, err
259: 	}
260: 	if stat.Sys() != nil {
261: 		return nil, stat.Sys().(error)
262: 	}
263: 
264: 	// Read the file contents and parse the tags
265: 	contents, err := fs.ReadFile(ffs, filePath)
266: 	if err != nil {
267: 		return nil, err
268: 	}
269: 	data := map[string]any{}
270: 	err = json.Unmarshal(contents, &data)
271: 	if err != nil {
272: 		return nil, err
273: 	}
274: 	p := metadata.Info{
275: 		Tags:            map[string][]string{},
276: 		AudioProperties: metadata.AudioProperties{},
277: 		HasPicture:      data["has_picture"] == "true",
278: 	}
279: 	if d, ok := data["duration"].(float64); ok {
280: 		p.AudioProperties.Duration = time.Duration(d) * time.Second
281: 	}
282: 	getInt := func(key string) int { v, _ := data[key].(float64); return int(v) }
283: 	p.AudioProperties.BitRate = getInt("bitrate")
284: 	p.AudioProperties.BitDepth = getInt("bitdepth")
285: 	p.AudioProperties.SampleRate = getInt("samplerate")
286: 	p.AudioProperties.Channels = getInt("channels")
287: 	for k, v := range data {
288: 		p.Tags[k] = []string{fmt.Sprintf("%v", v)}
289: 	}
290: 	file := ffs.MapFS[filePath]
291: 	p.FileInfo = &fakeFileInfo{path: filePath, tags: data, file: file}
292: 	return &p, nil
293: }
294: 
295: const (
296: 	fakeFileInfoMode      = "_mode"
297: 	fakeFileInfoSize      = "_size"
298: 	fakeFileInfoModTime   = "_modtime"
299: 	fakeFileInfoBirthTime = "_birthtime"
300: )
301: 
302: type fakeFileInfo struct {
303: 	path string
304: 	file *fstest.MapFile
305: 	tags map[string]any
306: }
307: 
308: func (ffi *fakeFileInfo) Name() string         { return path.Base(ffi.path) }
309: func (ffi *fakeFileInfo) Size() int64          { v, _ := ffi.tags[fakeFileInfoSize].(float64); return int64(v) }
310: func (ffi *fakeFileInfo) Mode() fs.FileMode    { return ffi.file.Mode }
311: func (ffi *fakeFileInfo) IsDir() bool          { return false }
312: func (ffi *fakeFileInfo) Sys() any             { return nil }
313: func (ffi *fakeFileInfo) ModTime() time.Time   { return ffi.file.ModTime }
314: func (ffi *fakeFileInfo) BirthTime() time.Time { return ffi.parseTime(fakeFileInfoBirthTime) }
315: func (ffi *fakeFileInfo) parseTime(key string) time.Time {
316: 	t, _ := time.Parse(time.RFC3339, ffi.tags[key].(string))
317: 	return t
318: }
