10: 	. "github.com/onsi/ginkgo/v2"
11: 	. "github.com/onsi/gomega"
12: )
13: 
14: type mockPhase struct {
15: 	num           int
16: 	produceFunc   func() ppl.Producer[int]
17: 	stagesFunc    func() []ppl.Stage[int]
18: 	finalizeFunc  func(error) error
19: 	descriptionFn func() string
20: }
21: 
22: func (m *mockPhase) producer() ppl.Producer[int] {
23: 	return m.produceFunc()
24: }
25: 
26: func (m *mockPhase) stages() []ppl.Stage[int] {
27: 	return m.stagesFunc()
28: }
29: 
30: func (m *mockPhase) finalize(err error) error {
31: 	return m.finalizeFunc(err)
32: }
33: 
34: func (m *mockPhase) description() string {
35: 	return m.descriptionFn()
36: }
37: 
38: var _ = Describe("runPhase", func() {
39: 	var (
40: 		ctx      context.Context
41: 		phaseNum int
42: 		phase    *mockPhase
43: 		sum      atomic.Int32
44: 	)
45: 
46: 	BeforeEach(func() {
47: 		ctx = context.Background()
48: 		phaseNum = 1
49: 		phase = &mockPhase{
50: 			num: 3,
51: 			produceFunc: func() ppl.Producer[int] {
52: 				return ppl.NewProducer(func(put func(int)) error {
53: 					for i := 1; i <= phase.num; i++ {
54: 						put(i)
55: 					}
56: 					return nil
57: 				})
58: 			},
59: 			stagesFunc: func() []ppl.Stage[int] {
60: 				return []ppl.Stage[int]{ppl.NewStage(func(i int) (int, error) {
61: 					sum.Add(int32(i))
62: 					return i, nil
63: 				})}
64: 			},
65: 			finalizeFunc: func(err error) error {
66: 				return err
67: 			},
68: 			descriptionFn: func() string {
69: 				return "Mock Phase"
70: 			},
71: 		}
72: 	})
73: 
74: 	It("should run the phase successfully", func() {
75: 		err := runPhase(ctx, phaseNum, phase)()
76: 		Expect(err).ToNot(HaveOccurred())
77: 		Expect(sum.Load()).To(Equal(int32(1 * 2 * 3)))
78: 	})
79: 
80: 	It("should log an error if the phase fails", func() {
81: 		phase.finalizeFunc = func(err error) error {
82: 			return errors.New("finalize error")
83: 		}
84: 		err := runPhase(ctx, phaseNum, phase)()
85: 		Expect(err).To(HaveOccurred())
86: 		Expect(err.Error()).To(ContainSubstring("finalize error"))
87: 	})
88: 
89: 	It("should count the tasks", func() {
90: 		counter, countStageFn := countTasks[int]()
91: 		phase.stagesFunc = func() []ppl.Stage[int] {
92: 			return []ppl.Stage[int]{ppl.NewStage(countStageFn, ppl.Name("count tasks"))}
93: 		}
94: 		err := runPhase(ctx, phaseNum, phase)()
95: 		Expect(err).ToNot(HaveOccurred())
96: 		Expect(counter.Load()).To(Equal(int64(3)))
97: 	})
98: })
