{"content":"1: package model
2: 
3: import (
4: 	"context"
5: 	"fmt"
6: 	"strconv"
7: 	"strings"
8: 	"time"
9: )
10: 
11: // ScanTarget represents a specific folder within a library to be scanned.
12: // NOTE: This struct is used as a map key, so it should only contain comparable types.
13: type ScanTarget struct {
14: 	LibraryID  int
15: 	FolderPath string // Relative path within the library, or "" for entire library
16: }
17: 
18: func (st ScanTarget) String() string {
19: 	return fmt.Sprintf("%d:%s", st.LibraryID, st.FolderPath)
20: }
21: 
22: // ScannerStatus holds information about the current scan status
23: type ScannerStatus struct {
24: 	Scanning    bool
25: 	LastScan    time.Time
26: 	Count       uint32
27: 	FolderCount uint32
28: 	LastError   string
29: 	ScanType    string
30: 	ElapsedTime time.Duration
31: }
32: 
33: type Scanner interface {
34: 	// ScanAll starts a scan of all libraries. This is a blocking operation.
35: 	ScanAll(ctx context.Context, fullScan bool) (warnings []string, err error)
36: 	// ScanFolders scans specific library/folder pairs, recursing into subdirectories.
37: 	// If targets is nil, it scans all libraries. This is a blocking operation.
38: 	ScanFolders(ctx context.Context, fullScan bool, targets []ScanTarget) (warnings []string, err error)
39: 	Status(context.Context) (*ScannerStatus, error)
40: }
41: 
42: // ParseTargets parses scan targets strings into ScanTarget structs.
43: // Example: []string{"1:Music/Rock", "2:Classical"}
44: func ParseTargets(libFolders []string) ([]ScanTarget, error) {
45: 	targets := make([]ScanTarget, 0, len(libFolders))
46: 
47: 	for _, part := range libFolders {
48: 		part = strings.TrimSpace(part)
49: 		if part == "" {
50: 			continue
51: 		}
52: 
53: 		// Split by the first colon
54: 		before, after, ok := strings.Cut(part, ":")
55: 		if !ok {
56: 			return nil, fmt.Errorf("invalid target format: %q (expected libraryID:folderPath)", part)
57: 		}
58: 
59: 		libIDStr := before
60: 		folderPath := after
61: 
62: 		libID, err := strconv.Atoi(libIDStr)
63: 		if err != nil {
64: 			return nil, fmt.Errorf("invalid library ID %q: %w", libIDStr, err)
65: 		}
66: 		if libID <= 0 {
67: 			return nil, fmt.Errorf("invalid library ID %q", libIDStr)
68: 		}
69: 
70: 		targets = append(targets, ScanTarget{
71: 			LibraryID:  libID,
72: 			FolderPath: folderPath,
73: 		})
74: 	}
75: 
76: 	if len(targets) == 0 {
77: 		return nil, fmt.Errorf("no valid targets found")
78: 	}
79: 
80: 	return targets, nil
81: }
